SET NAMES utf8mb4;
SET time_zone='+00:00';
START TRANSACTION;
ON DUPLICATE KEY UPDATE
 title=VALUES(title),slug=VALUES(slug),summary=VALUES(summary),content=VALUES(content),featured_image_alt=VALUES(featured_image_alt),meta_title=VALUES(meta_title),meta_description=VALUES(meta_description),updated_at=VALUES(updated_at);
COMMIT;
